// Summary: Tests EventPanel media attributes, slot visibility, overlay navigation structure, slot rendering, and class token hooks.

import '@testing-library/jest-dom';
import { render } from '@testing-library/react';
import * as React from 'react';
import { EventPanel, type EventPanelProps } from './EventPanel';

const baseProps: EventPanelProps = {
  imgSrc: 'https://example.com/event.jpg',
  imgAlt: 'Networking session at sunrise',
  subtitle: 'Featured',
  title: 'Global product summit',
  description: 'Collaborate with product leaders and attend hands-on sessions.',
  leftAction: <button type="button">Prev</button>,
  rightAction: <button type="button">Next</button>,
  labels: (
    <>
      <span>
        <span aria-hidden="true">🎟️</span>
        <span>Ticketed</span>
      </span>
      <span>
        <span aria-hidden="true">🌐</span>
        <span>Hybrid</span>
      </span>
    </>
  ),
  avatars: <div>Avatar roster</div>,
  buttons: (
    <>
      <button type="button">Register</button>
      <button type="button">Share</button>
    </>
  )
};

const renderEventPanel = (props?: Partial<EventPanelProps>) =>
  render(<EventPanel {...baseProps} {...props} />);

describe('EventPanel', () => {
  it('renders the image with alt text, default lazy loading, and no fetchpriority by default', () => {
    const { container } = renderEventPanel();
    const image = container.querySelector('[data-slot="_image"]');
    const mediaAttributesApplied =
      Boolean(image) &&
      image?.getAttribute('src') === baseProps.imgSrc &&
      image?.getAttribute('alt') === baseProps.imgAlt &&
      image?.getAttribute('loading') === 'lazy' &&
      image?.hasAttribute('fetchpriority') === false;
    expect(mediaAttributesApplied).toBe(true);
  });

  it('renders details and places buttons outside of the details container', () => {
    const { container } = renderEventPanel();
    const details = container.querySelector('[data-slot="_details"]');
    const buttons = container.querySelector('[data-slot="_buttons"]');
    const visibilityAndPlacement =
      Boolean(details?.className.includes('p-4')) &&
      Boolean(buttons) &&
      buttons?.parentElement !== details;
    expect(visibilityAndPlacement).toBe(true);
  });

  it('renders overlay navigation with left and right action slots', () => {
    const { container } = renderEventPanel();
    const actionsBar = container.querySelector('[data-slot="_actionsBar"]');
    const left = actionsBar?.querySelector('[data-slot="_left"]');
    const right = actionsBar?.querySelector('[data-slot="_right"]');
    const overlayStructure = Boolean(actionsBar && left && right);
    expect(overlayStructure).toBe(true);
  });

  it('renders labels with hidden icons, avatars content, and two buttons in the buttons slot', () => {
    const { container } = renderEventPanel();
    const labels = container.querySelector('[data-slot="_labels"]');
    const hiddenIcon = labels?.querySelector('[aria-hidden="true"]');
    const avatars = container.querySelector('[data-slot="_avatars"]');
    const buttons = container.querySelector('[data-slot="_buttons"]');
    const buttonsCount = buttons?.querySelectorAll('button').length === 2;
    const slotsRendered =
      Boolean(labels) &&
      Boolean(hiddenIcon) &&
      Boolean(avatars?.textContent?.includes('Avatar roster')) &&
      buttonsCount;
    expect(slotsRendered).toBe(true);
  });

  it('applies media sizing and overlay gradient classes to the respective slots', () => {
    const { container } = renderEventPanel();
    const media = container.querySelector('[data-slot="_media"]');
    const overlay = container.querySelector('[data-slot="_overlay"]');
    const classTokensApplied =
      Boolean(media?.className.includes('w-[390px]')) &&
      Boolean(media?.className.includes('group-data-[is-in-view=true]:scale-100')) &&
      Boolean(overlay?.className.includes('overlay-image-overlay'));
    expect(classTokensApplied).toBe(true);
  });
});
